func  (this *DydxCore) ParseTrade(trade any, optionalArgs ...any) any  {
    //
    // {
    //     "id": "02ac5b1f0000000200000002",
    //     "side": "BUY",
    //     "size": "0.0501",
    //     "price": "115732",
    //     "type": "LIMIT",
    //     "createdAt": "2025-07-25T05:11:09.800Z",
    //     "createdAtHeight": "44849951"
    // }
    //
    market := GetArg(optionalArgs, 0, nil)
    _ = market
    var timestamp any = this.Parse8601(this.SafeString(trade, "createdAt"))
    var symbol any = GetValue(market, "symbol")
    var price any = this.SafeString(trade, "price")
    var amount any = this.SafeString(trade, "size")
    var side any = this.SafeStringLower(trade, "side")
    var id any = this.SafeString(trade, "id")
    return this.SafeTrade(map[string]any {
        "id": id,
        "timestamp": timestamp,
        "datetime": this.Iso8601(timestamp),
        "symbol": symbol,
        "side": side,
        "price": price,
        "amount": amount,
        "cost": nil,
        "order": nil,
        "takerOrMaker": nil,
        "type": nil,
        "fee": nil,
        "info": trade,
    }, market)
}
